+                        let n = Python::attach(|py| {
+                            e.get_type(py)
+                                .name()
+                                .and_then(|s| s.extract::<String>())
+                                .unwrap_or_default()
+                        });
+                        panic!(
+                            "{name} axis=5 OOB: ours raised {n} but numpy succeeded"
+                        );
+                    }
+                }
+            }
